import type { PublicCard } from '../../../types';

export const startupFundamentalsCards: PublicCard[] = [
  // === Ideation & Validation (1-35) ===
  { id: 'dc-startup-0001', deck_id: 'deck-startup-fundamentals', front: 'What is the Lean Startup methodology?', back: 'A framework by Eric Ries that emphasizes rapid iteration through the Build-Measure-Learn loop. Start with hypotheses, build a minimal product, measure results, and learn whether to pivot or persevere. Reduces waste by validating ideas before heavy investment.', sort_order: 1 },
  { id: 'dc-startup-0002', deck_id: 'deck-startup-fundamentals', front: 'What is an MVP (Minimum Viable Product)?', back: 'The simplest version of a product that lets you test your core hypothesis with real users. It is not a prototype — it is a functional product with just enough features to gather validated learning. Examples: Dropbox demo video, Zappos manual shoe fulfillment.', sort_order: 2 },
  { id: 'dc-startup-0003', deck_id: 'deck-startup-fundamentals', front: 'What is problem-first thinking in startup ideation?', back: 'An approach where you start by identifying a real, painful problem before thinking about solutions. The best startups solve problems people already spend time, money, or effort trying to fix. Avoid building a solution in search of a problem.', sort_order: 3 },
  { id: 'dc-startup-0004', deck_id: 'deck-startup-fundamentals', front: 'What does "scratch your own itch" mean in startup context?', back: 'Building a product that solves a problem you personally experience. This gives you deep understanding of the user pain point and built-in motivation. Examples: Basecamp was built because 37signals needed a project management tool for their own consulting work.', sort_order: 4 },
  { id: 'dc-startup-0005', deck_id: 'deck-startup-fundamentals', front: 'What is problem-solution fit?', back: 'The stage where you have validated that a real problem exists and your proposed solution effectively addresses it. It comes before product-market fit and means customers acknowledge the problem and find your solution compelling enough to use.', sort_order: 5 },
  { id: 'dc-startup-0006', deck_id: 'deck-startup-fundamentals', front: 'What are customer discovery interviews?', back: 'Structured conversations with potential customers to understand their problems, needs, and behaviors. The goal is to listen and learn, not to pitch your product. Ask about past behavior and real experiences rather than hypothetical future actions.', sort_order: 6 },
  { id: 'dc-startup-0007', deck_id: 'deck-startup-fundamentals', front: 'What is the Build-Measure-Learn loop?', back: 'The core cycle of the Lean Startup. Build a minimal experiment, measure the results with actionable metrics, and learn whether your hypothesis was correct. The goal is to complete this loop as quickly as possible to accelerate validated learning.', sort_order: 7 },
  { id: 'dc-startup-0008', deck_id: 'deck-startup-fundamentals', front: 'What is a concierge MVP?', back: 'A validation technique where you manually deliver the service to each customer instead of building technology. It lets you test demand and learn about customer needs with zero development cost. Example: Food on the Table manually planned meals for early users before automating.', sort_order: 8 },
  { id: 'dc-startup-0009', deck_id: 'deck-startup-fundamentals', front: 'What is a Wizard of Oz MVP?', back: 'A type of MVP where the front end appears fully automated to the user, but a human is manually performing the work behind the scenes. It tests whether customers want the product without building the full technology. Useful for testing complex AI or automation ideas.', sort_order: 9 },
  { id: 'dc-startup-0010', deck_id: 'deck-startup-fundamentals', front: 'How can a landing page test validate a startup idea?', back: 'Create a simple landing page describing your value proposition with a sign-up or pre-order button. Drive traffic via ads and measure conversion rates. If people sign up or attempt to pay, it signals real demand. Tools like Unbounce or Carrd make this fast and cheap.', sort_order: 10 },
  { id: 'dc-startup-0011', deck_id: 'deck-startup-fundamentals', front: 'What is TAM (Total Addressable Market)?', back: 'The total revenue opportunity available if a product achieved 100% market share. It represents the entire demand for a product or service worldwide. Investors use TAM to assess the maximum potential of a business opportunity.', sort_order: 11 },
  { id: 'dc-startup-0012', deck_id: 'deck-startup-fundamentals', front: 'What is SAM (Serviceable Addressable Market)?', back: 'The portion of TAM that your product can realistically serve, given geographic, regulatory, or product constraints. It narrows the total market to the segment you can actually reach with your current business model and capabilities.', sort_order: 12 },
  { id: 'dc-startup-0013', deck_id: 'deck-startup-fundamentals', front: 'What is SOM (Serviceable Obtainable Market)?', back: 'The realistic portion of SAM you can capture in the near term, considering competition, resources, and go-to-market strategy. This is the most practical metric for early-stage startups to estimate achievable revenue in the first few years.', sort_order: 13 },
  { id: 'dc-startup-0014', deck_id: 'deck-startup-fundamentals', front: 'How do you conduct effective customer discovery interviews?', back: 'Use open-ended questions about past behavior, not future intentions. Ask about their biggest frustrations, current solutions, and how much they spend. Never pitch your idea — just listen. The Mom Test by Rob Fitzpatrick recommends asking questions even your mom would not lie about.', sort_order: 14 },
  { id: 'dc-startup-0015', deck_id: 'deck-startup-fundamentals', front: 'What is a competitive moat?', back: 'A sustainable competitive advantage that protects a business from competitors. Common moats include network effects, proprietary technology, brand loyalty, switching costs, economies of scale, and regulatory barriers. Warren Buffett popularized the concept.', sort_order: 15 },
  { id: 'dc-startup-0016', deck_id: 'deck-startup-fundamentals', front: 'What is an unfair advantage in a startup?', back: 'Something that cannot be easily copied or bought by competitors. Examples include unique expertise, a strong personal network, insider knowledge, proprietary data, or a dream team. It gives your startup a head start that others cannot replicate quickly.', sort_order: 16 },
  { id: 'dc-startup-0017', deck_id: 'deck-startup-fundamentals', front: 'What is a smoke test in startup validation?', back: 'A technique to measure customer interest before building anything. Common methods include fake door tests (a button for a feature that does not exist yet), pre-order pages, and ad campaigns driving to sign-up forms. It measures intent to buy, not just interest.', sort_order: 17 },
  { id: 'dc-startup-0018', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a hypothesis and an assumption in a startup?', back: 'A hypothesis is a testable statement about what you believe is true (e.g., "Users will pay $20/month for this"). An assumption is an untested belief underlying your business. Good founders identify their riskiest assumptions and convert them into testable hypotheses first.', sort_order: 18 },
  { id: 'dc-startup-0019', deck_id: 'deck-startup-fundamentals', front: 'What is the "Mom Test" in customer interviews?', back: 'A book by Rob Fitzpatrick that teaches how to ask questions so that even your mom would give honest, useful feedback. The key rules: talk about their life instead of your idea, ask about specifics in the past instead of opinions about the future, and listen more than you talk.', sort_order: 19 },
  { id: 'dc-startup-0020', deck_id: 'deck-startup-fundamentals', front: 'What are the top-down vs bottom-up approaches to market sizing?', back: 'Top-down starts with a large market figure and narrows it based on your addressable segment. Bottom-up starts with unit economics (price x number of potential customers you can reach). Bottom-up is generally more credible for startups because it is grounded in real numbers.', sort_order: 20 },
  { id: 'dc-startup-0021', deck_id: 'deck-startup-fundamentals', front: 'What is a leap-of-faith assumption?', back: 'The riskiest assumption underlying your startup that, if proven wrong, would make the entire business model fail. Examples: "People will share photos with strangers" (Instagram) or "People will sleep in a stranger house" (Airbnb). Test these first.', sort_order: 21 },
  { id: 'dc-startup-0022', deck_id: 'deck-startup-fundamentals', front: 'How do you identify a good startup problem to solve?', back: 'Look for problems that are frequent (happen often), intense (cause real pain), and that people are already paying money or significant effort to solve. The best problems exist at the intersection of personal experience, market demand, and your unique skill set.', sort_order: 22 },
  { id: 'dc-startup-0023', deck_id: 'deck-startup-fundamentals', front: 'What is a value hypothesis?', back: 'A testable assumption about whether your product delivers enough value that customers will use it and pay for it. It answers the question: "Does this product solve a real problem well enough that people will choose it over alternatives?" Validate this before a growth hypothesis.', sort_order: 23 },
  { id: 'dc-startup-0024', deck_id: 'deck-startup-fundamentals', front: 'What is a growth hypothesis?', back: 'A testable assumption about how new customers will discover and adopt your product. It addresses whether your product can spread through viral sharing, word of mouth, paid acquisition, or other channels. Test this after validating your value hypothesis.', sort_order: 24 },
  { id: 'dc-startup-0025', deck_id: 'deck-startup-fundamentals', front: 'What is competitive analysis for startups?', back: 'A systematic assessment of direct and indirect competitors including their strengths, weaknesses, pricing, features, and market positioning. Use it to find gaps in the market and differentiate your offering. Tools include SWOT analysis, feature comparison matrices, and Porter Five Forces.', sort_order: 25 },
  { id: 'dc-startup-0026', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between direct and indirect competitors?', back: 'Direct competitors offer a similar product solving the same problem (Uber vs Lyft). Indirect competitors solve the same problem differently (Uber vs public transit). When validating a market, consider both — indirect competitors often reveal that demand exists for a solution.', sort_order: 26 },
  { id: 'dc-startup-0027', deck_id: 'deck-startup-fundamentals', front: 'What is the "hair on fire" problem concept?', back: 'A problem so urgent and painful that customers will use even an imperfect solution to fix it. These problems lead to the fastest product adoption because the customer is already actively seeking a solution. They represent the best opportunities for MVP-stage startups.', sort_order: 27 },
  { id: 'dc-startup-0028', deck_id: 'deck-startup-fundamentals', front: 'What is a pre-mortem exercise for startup ideas?', back: 'A mental exercise where you imagine your startup has failed and work backward to identify the most likely reasons. This helps surface hidden assumptions and risks before you invest significant time and money. It is more effective than optimistic forward-looking planning alone.', sort_order: 28 },
  { id: 'dc-startup-0029', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a feature and a product for MVP purposes?', back: 'A feature is a single capability (e.g., photo filters). A product is a complete solution that delivers value on its own. A common mistake is building a feature disguised as a product. Your MVP should be a standalone product that solves one core problem, not a collection of features.', sort_order: 29 },
  { id: 'dc-startup-0030', deck_id: 'deck-startup-fundamentals', front: 'What is validated learning?', back: 'The process of demonstrating empirically that a team has discovered valuable truths about a business through experiments. It is the primary unit of progress in the Lean Startup. Each experiment should produce measurable evidence that confirms or denies a specific hypothesis.', sort_order: 30 },
  { id: 'dc-startup-0031', deck_id: 'deck-startup-fundamentals', front: 'What are vanity metrics vs actionable metrics?', back: 'Vanity metrics look good on paper but do not drive decisions (e.g., total sign-ups, page views). Actionable metrics help you make business decisions (e.g., conversion rate, retention rate, revenue per user). Focus on metrics that inform whether to pivot or persevere.', sort_order: 31 },
  { id: 'dc-startup-0032', deck_id: 'deck-startup-fundamentals', front: 'What is the innovator dilemma relevant to startup opportunities?', back: 'Clayton Christensen showed that large companies often ignore emerging markets because they are too small. This creates opportunities for startups to enter underserved segments with simpler, cheaper solutions and eventually move upmarket. Disruption comes from below.', sort_order: 32 },
  { id: 'dc-startup-0033', deck_id: 'deck-startup-fundamentals', front: 'What is a beachhead market?', back: 'A small, well-defined market segment you target first before expanding. Coined by Geoffrey Moore, it means focusing all resources on winning one niche completely, then leveraging that success to enter adjacent markets. Facebook started with Harvard students before expanding.', sort_order: 33 },
  { id: 'dc-startup-0034', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a vision, strategy, and product in a startup?', back: 'The vision is the long-term goal that rarely changes. The strategy is the plan to achieve the vision and may pivot based on learning. The product is the concrete implementation of the strategy and changes frequently through iteration. Vision stays fixed while tactics evolve.', sort_order: 34 },
  { id: 'dc-startup-0035', deck_id: 'deck-startup-fundamentals', front: 'What is a design sprint and how does it help validation?', back: 'A five-day process developed at Google Ventures to rapidly prototype and test ideas with real users. Day 1: Map the problem. Day 2: Sketch solutions. Day 3: Decide on the best. Day 4: Build a realistic prototype. Day 5: Test with five users. Compresses months of work into one week.', sort_order: 35 },

  // === Business Models & Strategy (36-70) ===
  { id: 'dc-startup-0036', deck_id: 'deck-startup-fundamentals', front: 'What is a SaaS (Software as a Service) business model?', back: 'A model where software is hosted centrally and customers pay a recurring subscription (monthly or annually) to access it. Key metrics include MRR, churn, and LTV. Examples: Slack, Salesforce, Zoom. SaaS is attractive because of predictable recurring revenue.', sort_order: 36 },
  { id: 'dc-startup-0037', deck_id: 'deck-startup-fundamentals', front: 'What is a marketplace business model?', back: 'A platform that connects buyers and sellers, earning revenue through transaction fees or commissions. The main challenge is solving the chicken-and-egg problem: you need both supply and demand. Examples: Airbnb, Uber, Etsy. Network effects make marketplaces defensible once established.', sort_order: 37 },
  { id: 'dc-startup-0038', deck_id: 'deck-startup-fundamentals', front: 'What is a freemium business model?', back: 'A model offering a free basic tier to attract users and a paid premium tier with advanced features. The free tier drives acquisition while the paid tier generates revenue. Typically 2-5% of free users convert to paid. Examples: Spotify, Dropbox, Slack.', sort_order: 38 },
  { id: 'dc-startup-0039', deck_id: 'deck-startup-fundamentals', front: 'What is CAC (Customer Acquisition Cost)?', back: 'The total cost of acquiring a new customer, including marketing, sales, and onboarding expenses. Calculated as total acquisition spend divided by the number of new customers acquired. A healthy business needs LTV to be at least 3x CAC.', sort_order: 39 },
  { id: 'dc-startup-0040', deck_id: 'deck-startup-fundamentals', front: 'What is LTV (Lifetime Value)?', back: 'The total revenue a business expects to earn from a single customer over the entire relationship. Calculated as average revenue per user multiplied by average customer lifespan. LTV should be significantly higher than CAC for a sustainable business — ideally 3x or more.', sort_order: 40 },
  { id: 'dc-startup-0041', deck_id: 'deck-startup-fundamentals', front: 'What is the LTV:CAC ratio and why does it matter?', back: 'The ratio of customer lifetime value to customer acquisition cost. A ratio of 3:1 or higher is considered healthy for most startups. Below 1:1 means you lose money on every customer. Above 5:1 may mean you are underinvesting in growth.', sort_order: 41 },
  { id: 'dc-startup-0042', deck_id: 'deck-startup-fundamentals', front: 'What is churn rate?', back: 'The percentage of customers who stop using your product or cancel their subscription during a given period. Monthly churn of 5% means you lose about 46% of customers per year. Reducing churn is often more impactful than acquiring new customers.', sort_order: 42 },
  { id: 'dc-startup-0043', deck_id: 'deck-startup-fundamentals', front: 'What is the CAC payback period?', back: 'The number of months it takes to recover the cost of acquiring a customer through their revenue contributions. A payback period under 12 months is generally considered healthy for SaaS businesses. Shorter payback means faster cash flow and less risk.', sort_order: 43 },
  { id: 'dc-startup-0044', deck_id: 'deck-startup-fundamentals', front: 'What is value-based pricing?', back: 'Setting prices based on the perceived value to the customer rather than the cost to produce. If your product saves a customer $1,000/month, charging $200/month is justified regardless of your costs. This approach captures more value and often results in higher margins.', sort_order: 44 },
  { id: 'dc-startup-0045', deck_id: 'deck-startup-fundamentals', front: 'What is penetration pricing strategy?', back: 'Setting a low initial price to quickly gain market share and attract a large customer base. Once established, prices can be raised. Useful in competitive markets where network effects matter. Risk: customers may anchor on the low price and resist increases.', sort_order: 45 },
  { id: 'dc-startup-0046', deck_id: 'deck-startup-fundamentals', front: 'What is price skimming strategy?', back: 'Launching at a high price targeting early adopters willing to pay a premium, then gradually lowering the price to reach broader segments. Common in technology and innovation-driven products. Apple uses this approach with new iPhone launches.', sort_order: 46 },
  { id: 'dc-startup-0047', deck_id: 'deck-startup-fundamentals', front: 'What is the Business Model Canvas?', back: 'A strategic management tool by Alexander Osterwalder that maps a business model on one page using nine blocks: Key Partners, Key Activities, Key Resources, Value Propositions, Customer Relationships, Channels, Customer Segments, Cost Structure, and Revenue Streams.', sort_order: 47 },
  { id: 'dc-startup-0048', deck_id: 'deck-startup-fundamentals', front: 'What is the Lean Canvas?', back: 'An adaptation of the Business Model Canvas by Ash Maurya, designed specifically for startups. It replaces Key Partners, Key Activities, Key Resources, and Customer Relationships with Problem, Solution, Key Metrics, and Unfair Advantage. Focuses on risk and uncertainty.', sort_order: 48 },
  { id: 'dc-startup-0049', deck_id: 'deck-startup-fundamentals', front: 'What is recurring revenue and why is it valuable?', back: 'Revenue that repeats predictably through subscriptions or ongoing contracts. It is highly valued because it provides predictable cash flow, higher customer lifetime value, and easier financial forecasting. Recurring revenue businesses typically receive higher valuations from investors.', sort_order: 49 },
  { id: 'dc-startup-0050', deck_id: 'deck-startup-fundamentals', front: 'What is MRR (Monthly Recurring Revenue)?', back: 'The predictable revenue a subscription business earns each month. Calculated by multiplying the number of paying customers by the average revenue per user. MRR growth rate is one of the most important metrics for SaaS startups when fundraising.', sort_order: 50 },
  { id: 'dc-startup-0051', deck_id: 'deck-startup-fundamentals', front: 'What is ARR (Annual Recurring Revenue)?', back: 'The annualized value of recurring subscription revenue, calculated as MRR multiplied by 12. It is the standard metric for measuring the size and growth of SaaS businesses. Investors often use ARR multiples to value SaaS companies.', sort_order: 51 },
  { id: 'dc-startup-0052', deck_id: 'deck-startup-fundamentals', front: 'What are network effects?', back: 'When a product becomes more valuable as more people use it. Direct network effects: each user makes it better for all others (telephone, social media). Indirect network effects: more users attract complementary products (more iPhone users attract more app developers).', sort_order: 52 },
  { id: 'dc-startup-0053', deck_id: 'deck-startup-fundamentals', front: 'What is a platform business model?', back: 'A model that creates value by facilitating exchanges between two or more interdependent groups. Unlike traditional linear businesses, platforms do not own inventory — they connect producers and consumers. Examples: Apple App Store, YouTube, Amazon Marketplace.', sort_order: 53 },
  { id: 'dc-startup-0054', deck_id: 'deck-startup-fundamentals', front: 'What is the chicken-and-egg problem in marketplaces?', back: 'The challenge of needing both supply (sellers) and demand (buyers) for a marketplace to function, but neither side wants to join without the other. Solutions include subsidizing one side, starting with a niche, or creating standalone value for one side first.', sort_order: 54 },
  { id: 'dc-startup-0055', deck_id: 'deck-startup-fundamentals', front: 'What is unit economics?', back: 'The revenue and costs associated with a single unit of your business (one customer, one transaction, one product sold). Healthy unit economics mean you earn more from each customer than it costs to acquire and serve them. Negative unit economics are unsustainable long term.', sort_order: 55 },
  { id: 'dc-startup-0056', deck_id: 'deck-startup-fundamentals', front: 'What is an advertising-based business model?', back: 'A model where the product is offered free to users, and revenue comes from advertisers paying to reach that user base. Requires massive scale to be profitable. Key metrics include DAU/MAU, engagement, and CPM. Examples: Google Search, Facebook, YouTube.', sort_order: 56 },
  { id: 'dc-startup-0057', deck_id: 'deck-startup-fundamentals', front: 'What is a transaction fee business model?', back: 'A model where the platform takes a percentage of each transaction it facilitates. Common in payment processors, marketplaces, and fintech. Examples: Stripe (2.9% + 30 cents), Airbnb (3% host fee + up to 14% guest fee), PayPal.', sort_order: 57 },
  { id: 'dc-startup-0058', deck_id: 'deck-startup-fundamentals', front: 'What is cost-plus pricing?', back: 'A pricing strategy where you calculate your total cost to deliver the product and add a markup percentage. Simple to implement but often leaves money on the table because it ignores the perceived value to the customer. More common in manufacturing than in software.', sort_order: 58 },
  { id: 'dc-startup-0059', deck_id: 'deck-startup-fundamentals', front: 'What is a subscription business model?', back: 'A model where customers pay a recurring fee (weekly, monthly, or annually) for continued access to a product or service. Benefits include predictable revenue, higher LTV, and lower churn compared to one-time purchases. Examples: Netflix, Dollar Shave Club, Adobe Creative Cloud.', sort_order: 59 },
  { id: 'dc-startup-0060', deck_id: 'deck-startup-fundamentals', front: 'What are switching costs and why do they matter?', back: 'The costs (financial, time, effort, data migration) a customer incurs when moving to a competitor. High switching costs create customer lock-in and reduce churn. Enterprise software often has high switching costs, making it a strong defensive moat.', sort_order: 60 },
  { id: 'dc-startup-0061', deck_id: 'deck-startup-fundamentals', front: 'What is gross margin and why is it important for startups?', back: 'Revenue minus cost of goods sold, divided by revenue. High gross margins (70%+) indicate a scalable business because most revenue flows to the bottom line. Software businesses typically have 80-90% gross margins, while physical product businesses might have 30-50%.', sort_order: 61 },
  { id: 'dc-startup-0062', deck_id: 'deck-startup-fundamentals', front: 'What is a razor-and-blade business model?', back: 'A model where the primary product is sold at low cost or a loss, while recurring consumables or accessories generate the main profit. Named after Gillette selling cheap razors and expensive blades. Modern examples: printers and ink cartridges, game consoles and games.', sort_order: 62 },
  { id: 'dc-startup-0063', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between B2B and B2C startups?', back: 'B2B (business-to-business) sells to companies, typically with longer sales cycles, higher contract values, and relationship-based selling. B2C (business-to-consumer) sells to individuals, with shorter sales cycles, lower price points, and volume-based growth.', sort_order: 63 },
  { id: 'dc-startup-0064', deck_id: 'deck-startup-fundamentals', front: 'What is negative churn?', back: 'When expansion revenue from existing customers (through upsells, cross-sells, or usage increases) exceeds the revenue lost from churned customers. Negative churn means your revenue grows even without adding new customers. It is a powerful indicator of product-market fit.', sort_order: 64 },
  { id: 'dc-startup-0065', deck_id: 'deck-startup-fundamentals', front: 'What is a value proposition?', back: 'A clear statement of why a customer should choose your product over alternatives. It defines the specific benefit you deliver, who you deliver it to, and how you do it differently. A strong value proposition addresses a specific pain point and communicates measurable results.', sort_order: 65 },
  { id: 'dc-startup-0066', deck_id: 'deck-startup-fundamentals', front: 'What is the land-and-expand sales strategy?', back: 'Starting with a small initial deal or free tier within an organization, then expanding usage across teams and departments over time. Common in SaaS B2B. Slack, Dropbox, and Atlassian all grew this way — individual teams adopted the product and it spread organically.', sort_order: 66 },
  { id: 'dc-startup-0067', deck_id: 'deck-startup-fundamentals', front: 'What are economies of scale?', back: 'Cost advantages that companies gain as production volume increases, because fixed costs are spread across more units. Startups that achieve economies of scale can offer lower prices or higher margins. This creates a competitive moat against smaller competitors.', sort_order: 67 },
  { id: 'dc-startup-0068', deck_id: 'deck-startup-fundamentals', front: 'What is the flywheel effect in business strategy?', back: 'A self-reinforcing cycle where each element of the business feeds the next, creating compounding momentum. Amazon example: lower prices attract more customers, more customers attract more sellers, more sellers increase selection, which allows even lower prices.', sort_order: 68 },
  { id: 'dc-startup-0069', deck_id: 'deck-startup-fundamentals', front: 'What is revenue diversification and why does it matter?', back: 'Having multiple sources of revenue rather than depending on a single one. It reduces risk if one revenue stream declines. However, early-stage startups should usually focus on one revenue stream until it is working well before diversifying.', sort_order: 69 },
  { id: 'dc-startup-0070', deck_id: 'deck-startup-fundamentals', front: 'What is a loss leader strategy?', back: 'Selling a product at a loss to attract customers who then purchase profitable products or services. Amazon sold Kindle devices at near cost to drive ebook and Prime subscription sales. Startups use this when the lifetime value of the customer relationship exceeds the initial loss.', sort_order: 70 },

  // === Product Development (71-100) ===
  { id: 'dc-startup-0071', deck_id: 'deck-startup-fundamentals', front: 'What is product-market fit?', back: 'The point where your product satisfies strong market demand. Marc Andreessen describes it as "being in a good market with a product that can satisfy that market." Signs include organic growth, high retention, and customers who would be very disappointed if the product disappeared.', sort_order: 71 },
  { id: 'dc-startup-0072', deck_id: 'deck-startup-fundamentals', front: 'What is the Sean Ellis test for product-market fit?', back: 'Ask users: "How would you feel if you could no longer use this product?" If 40% or more answer "very disappointed," you likely have product-market fit. This survey-based test was developed by Sean Ellis and is used widely by growth-stage startups.', sort_order: 72 },
  { id: 'dc-startup-0073', deck_id: 'deck-startup-fundamentals', front: 'What is Agile development?', back: 'An iterative approach to software development that emphasizes flexibility, collaboration, and delivering working software in short cycles (sprints). Instead of planning everything upfront (Waterfall), teams adapt to changes and continuously deliver value based on user feedback.', sort_order: 73 },
  { id: 'dc-startup-0074', deck_id: 'deck-startup-fundamentals', front: 'What is a sprint in Agile development?', back: 'A fixed time period (usually 1-2 weeks) during which a team completes a set amount of work. Each sprint includes planning, daily standups, execution, a review, and a retrospective. Sprints keep teams focused and enable frequent delivery of working features.', sort_order: 74 },
  { id: 'dc-startup-0075', deck_id: 'deck-startup-fundamentals', front: 'What is a user story in product development?', back: 'A short, informal description of a feature from the end user perspective, written as: "As a [type of user], I want [goal] so that [benefit]." User stories focus on value delivered to the user rather than technical specifications. They keep development customer-centric.', sort_order: 75 },
  { id: 'dc-startup-0076', deck_id: 'deck-startup-fundamentals', front: 'What is the RICE framework for feature prioritization?', back: 'A scoring model that evaluates features by Reach (how many users are affected), Impact (how much it affects each user), Confidence (how certain you are about estimates), and Effort (how much work it requires). Score = (Reach x Impact x Confidence) / Effort.', sort_order: 76 },
  { id: 'dc-startup-0077', deck_id: 'deck-startup-fundamentals', front: 'What is the MoSCoW method for prioritization?', back: 'A technique that categorizes features into Must have (critical), Should have (important but not vital), Could have (nice to have), and Will not have (out of scope for now). Helps teams focus on essentials and make trade-off decisions when resources are limited.', sort_order: 77 },
  { id: 'dc-startup-0078', deck_id: 'deck-startup-fundamentals', front: 'What is the Kano model for feature analysis?', back: 'A model classifying features into three categories: Basic (expected, cause dissatisfaction if missing), Performance (satisfaction proportional to quality), and Delighters (unexpected features that create excitement). Helps teams invest in features with the highest impact on satisfaction.', sort_order: 78 },
  { id: 'dc-startup-0079', deck_id: 'deck-startup-fundamentals', front: 'What is user onboarding and why is it critical?', back: 'The process of guiding new users to experience the core value of your product as quickly as possible. Poor onboarding is a top reason for churn. Best practices include reducing time-to-value, using progressive disclosure, and celebrating small wins during the first session.', sort_order: 79 },
  { id: 'dc-startup-0080', deck_id: 'deck-startup-fundamentals', front: 'What is the "aha moment" in product design?', back: 'The point when a new user first realizes the value of your product. For Facebook, it was adding 7 friends in 10 days. For Slack, it was sending 2,000 team messages. Identifying and optimizing the path to this moment dramatically improves activation and retention rates.', sort_order: 80 },
  { id: 'dc-startup-0081', deck_id: 'deck-startup-fundamentals', front: 'What is technical debt?', back: 'The implied cost of future rework caused by choosing quick, easy solutions now instead of better approaches that take longer. Some technical debt is strategic (shipping faster to validate). Too much creates maintenance burden, slow development, and unreliable software.', sort_order: 81 },
  { id: 'dc-startup-0082', deck_id: 'deck-startup-fundamentals', front: 'When should a startup build vs buy technology?', back: 'Build when the technology is your core competitive advantage or does not exist in the market. Buy (or use existing tools/APIs) when it is a commodity or not core to your value proposition. Early-stage startups should almost always buy non-core components to focus limited resources.', sort_order: 82 },
  { id: 'dc-startup-0083', deck_id: 'deck-startup-fundamentals', front: 'What is a product roadmap?', back: 'A strategic document that outlines the vision, direction, and planned evolution of a product over time. For startups, keep it flexible — a roadmap is a plan, not a promise. Focus on outcomes and problems to solve rather than a fixed list of features.', sort_order: 83 },
  { id: 'dc-startup-0084', deck_id: 'deck-startup-fundamentals', front: 'What is retention rate and why is it the most important metric?', back: 'The percentage of users who continue using your product over time. High retention means your product delivers ongoing value. Without strong retention, growth is like filling a leaky bucket — you acquire users but they leave. Retention is the foundation of sustainable growth.', sort_order: 84 },
  { id: 'dc-startup-0085', deck_id: 'deck-startup-fundamentals', front: 'What is a daily active user to monthly active user (DAU/MAU) ratio?', back: 'A measure of how frequently users engage with your product. A ratio above 50% indicates high stickiness (users come back most days). Social media apps like Facebook aim for 60%+. A low ratio suggests your product is useful but not habit-forming.', sort_order: 85 },
  { id: 'dc-startup-0086', deck_id: 'deck-startup-fundamentals', front: 'What is the concept of iteration in product development?', back: 'Continuously improving your product through repeated cycles of building, measuring, and learning. Each iteration refines the product based on real user feedback and data. Successful startups iterate rapidly — shipping small improvements weekly rather than big releases quarterly.', sort_order: 86 },
  { id: 'dc-startup-0087', deck_id: 'deck-startup-fundamentals', front: 'What is scope creep and how do startups avoid it?', back: 'The gradual expansion of a project beyond its original goals, adding features and complexity without clear justification. Avoid it by defining clear success criteria upfront, saying no to non-essential features, and maintaining a disciplined product backlog with strict prioritization.', sort_order: 87 },
  { id: 'dc-startup-0088', deck_id: 'deck-startup-fundamentals', front: 'What is a North Star metric?', back: 'The single metric that best captures the core value your product delivers to customers. For Airbnb it is nights booked, for Facebook it is daily active users, for Slack it is messages sent. Aligning the team around one North Star metric improves focus and decision-making.', sort_order: 88 },
  { id: 'dc-startup-0089', deck_id: 'deck-startup-fundamentals', front: 'What is progressive disclosure in UX design?', back: 'A design technique that shows only the essential information and options upfront, revealing complexity gradually as users need it. It reduces cognitive overload for new users while keeping advanced features accessible for power users. Critical for products with complex functionality.', sort_order: 89 },
  { id: 'dc-startup-0090', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between UX and UI?', back: 'UX (User Experience) is the overall feel and flow of using a product — including ease of use, efficiency, and satisfaction. UI (User Interface) is the visual design — buttons, colors, typography, and layout. Good UX with bad UI is usable but ugly; good UI with bad UX is pretty but frustrating.', sort_order: 90 },
  { id: 'dc-startup-0091', deck_id: 'deck-startup-fundamentals', front: 'What is a feature flag (feature toggle)?', back: 'A technique that lets you enable or disable features without deploying new code. Useful for A/B testing, gradual rollouts, and quickly turning off problematic features. Tools like LaunchDarkly or Flagsmith make this easy. Essential for rapid experimentation at scale.', sort_order: 91 },
  { id: 'dc-startup-0092', deck_id: 'deck-startup-fundamentals', front: 'What is continuous deployment?', back: 'A practice where code changes are automatically deployed to production after passing automated tests. It enables teams to ship multiple times per day with confidence. Combined with feature flags, it lets startups iterate and experiment faster than competitors.', sort_order: 92 },
  { id: 'dc-startup-0093', deck_id: 'deck-startup-fundamentals', front: 'What is a product-led growth (PLG) strategy?', back: 'A go-to-market strategy where the product itself is the primary driver of acquisition, activation, and expansion. Users can try and get value from the product without talking to sales. Examples: Slack, Zoom, Calendly. Requires an excellent self-serve experience and low friction onboarding.', sort_order: 93 },
  { id: 'dc-startup-0094', deck_id: 'deck-startup-fundamentals', front: 'What is a cohort analysis?', back: 'Grouping users by their start date (or another shared trait) and tracking their behavior over time. It reveals whether newer cohorts retain better than older ones, indicating product improvements. Essential for understanding true retention trends rather than aggregated averages.', sort_order: 94 },
  { id: 'dc-startup-0095', deck_id: 'deck-startup-fundamentals', front: 'What is the Jobs-to-be-Done (JTBD) framework?', back: 'A theory that customers "hire" products to accomplish specific jobs in their lives. Focus on the job (e.g., "help me pass time during my commute") rather than demographics. Milkshake example by Clayton Christensen: people "hired" milkshakes for a boring commute, not because they liked dairy.', sort_order: 95 },
  { id: 'dc-startup-0096', deck_id: 'deck-startup-fundamentals', front: 'What is a product analytics tool and which ones do startups use?', back: 'Software that tracks user behavior within your product. Popular tools include Mixpanel (event tracking), Amplitude (product analytics), PostHog (open source), and Google Analytics. They help you understand which features are used, where users drop off, and what drives conversion.', sort_order: 96 },
  { id: 'dc-startup-0097', deck_id: 'deck-startup-fundamentals', front: 'What is a beta launch strategy?', back: 'Releasing your product to a limited group of early users before a full public launch. Benefits include gathering feedback, finding bugs, and building a community of advocates. Offer beta users special access or pricing in exchange for their time and honest feedback.', sort_order: 97 },
  { id: 'dc-startup-0098', deck_id: 'deck-startup-fundamentals', front: 'What is time-to-value (TTV) and why does it matter?', back: 'The time it takes for a new user to experience the core benefit of your product. Shorter TTV leads to higher activation and retention rates. Optimize by simplifying onboarding, using templates or sample data, and guiding users directly to the most valuable feature first.', sort_order: 98 },
  { id: 'dc-startup-0099', deck_id: 'deck-startup-fundamentals', front: 'What is a feedback loop in product development?', back: 'A mechanism for collecting user input and turning it into product improvements. Effective feedback loops include in-app surveys, user interviews, support tickets, analytics data, and feature request boards. The faster the loop, the faster you improve the product.', sort_order: 99 },
  { id: 'dc-startup-0100', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a monolith and microservices architecture?', back: 'A monolith is a single, unified codebase where all components are tightly coupled. Microservices split the application into small, independent services. Startups should almost always start with a monolith for speed and simplicity, then migrate to microservices only when scale demands it.', sort_order: 100 },

  // === Fundraising & Finance (101-145) ===
  { id: 'dc-startup-0101', deck_id: 'deck-startup-fundamentals', front: 'What is bootstrapping a startup?', back: 'Funding your business with personal savings, revenue, or minimal external capital instead of raising from investors. Benefits include full ownership, no dilution, and forced discipline. Drawbacks include slower growth and personal financial risk. Mailchimp bootstrapped to $12B.', sort_order: 101 },
  { id: 'dc-startup-0102', deck_id: 'deck-startup-fundamentals', front: 'What is angel investing?', back: 'High-net-worth individuals who invest personal money in early-stage startups in exchange for equity. Angel investments typically range from $25K to $500K. Angels often provide mentorship and connections in addition to capital. Many are former entrepreneurs themselves.', sort_order: 102 },
  { id: 'dc-startup-0103', deck_id: 'deck-startup-fundamentals', front: 'What is venture capital (VC)?', back: 'Professional investment firms that invest pooled money from limited partners into high-growth startups in exchange for equity. VCs invest larger amounts than angels, typically $1M-$100M+. They expect outsized returns (10x+) and usually seek board seats and significant influence.', sort_order: 103 },
  { id: 'dc-startup-0104', deck_id: 'deck-startup-fundamentals', front: 'What is a pre-seed funding round?', back: 'The earliest formal fundraising stage, typically $50K-$500K, used to validate an idea or build an initial prototype. Investors are usually friends, family, angel investors, or pre-seed focused funds. The startup may only have a team and an idea at this stage.', sort_order: 104 },
  { id: 'dc-startup-0105', deck_id: 'deck-startup-fundamentals', front: 'What is a seed funding round?', back: 'An early funding round, typically $500K-$3M, to build the product, hire initial team members, and find product-market fit. Investors include angel investors, seed-stage VC funds, and accelerators. The startup usually has a working MVP and early traction.', sort_order: 105 },
  { id: 'dc-startup-0106', deck_id: 'deck-startup-fundamentals', front: 'What is a Series A funding round?', back: 'Typically the first major institutional VC round, ranging from $3M-$15M. At this stage, the startup should demonstrate product-market fit, meaningful revenue or growth metrics, and a clear path to scaling. Investors expect a proven business model and a plan for rapid growth.', sort_order: 106 },
  { id: 'dc-startup-0107', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between Series A, B, and C rounds?', back: 'Series A focuses on scaling a proven product ($3-15M). Series B funds rapid expansion, hiring, and market penetration ($15-50M). Series C and beyond finance further scale, international expansion, or pre-IPO growth ($50M+). Each round involves higher valuations and larger checks.', sort_order: 107 },
  { id: 'dc-startup-0108', deck_id: 'deck-startup-fundamentals', front: 'What is a term sheet?', back: 'A non-binding document outlining the key terms of an investment deal, including valuation, investment amount, equity percentage, board seats, liquidation preferences, and anti-dilution provisions. It serves as the basis for negotiation before drafting final legal agreements.', sort_order: 108 },
  { id: 'dc-startup-0109', deck_id: 'deck-startup-fundamentals', front: 'What is pre-money valuation?', back: 'The value of a company immediately before receiving a new investment. If a startup has a pre-money valuation of $4M and raises $1M, the post-money valuation is $5M. The investor owns 20% ($1M / $5M). Pre-money valuation is a key negotiation point in fundraising.', sort_order: 109 },
  { id: 'dc-startup-0110', deck_id: 'deck-startup-fundamentals', front: 'What is post-money valuation?', back: 'The value of a company immediately after receiving a new investment. Calculated as pre-money valuation plus the investment amount. Post-money valuation determines what percentage of the company each investor owns after the round closes.', sort_order: 110 },
  { id: 'dc-startup-0111', deck_id: 'deck-startup-fundamentals', front: 'What is a cap table (capitalization table)?', back: 'A spreadsheet showing the ownership structure of a company, including shares held by founders, investors, employees, and option holders. It tracks all equity issuances, conversions, and dilution over time. Keeping a clean cap table is essential for fundraising.', sort_order: 111 },
  { id: 'dc-startup-0112', deck_id: 'deck-startup-fundamentals', front: 'What is equity dilution?', back: 'The reduction in existing shareholders ownership percentage when new shares are issued (e.g., during a funding round). If a founder owns 100% and gives 20% to investors, the founder is diluted to 80%. Dilution is expected but founders should monitor cumulative impact.', sort_order: 112 },
  { id: 'dc-startup-0113', deck_id: 'deck-startup-fundamentals', front: 'What is a SAFE (Simple Agreement for Future Equity)?', back: 'An investment instrument created by Y Combinator where an investor provides capital in exchange for the right to receive equity at a future priced round. SAFEs are simpler and cheaper than convertible notes — no interest rate, no maturity date. They include a valuation cap and/or discount.', sort_order: 113 },
  { id: 'dc-startup-0114', deck_id: 'deck-startup-fundamentals', front: 'What is a convertible note?', back: 'A short-term debt instrument that converts into equity at a future funding round. Unlike a SAFE, it has an interest rate and maturity date. Conversion terms include a valuation cap and/or discount rate. If the note reaches maturity without a conversion event, repayment may be required.', sort_order: 114 },
  { id: 'dc-startup-0115', deck_id: 'deck-startup-fundamentals', front: 'What is a valuation cap on a SAFE or convertible note?', back: 'The maximum valuation at which the investment converts to equity. If the cap is $5M and the Series A prices the company at $10M, the SAFE investor converts at $5M, getting twice as many shares. It protects early investors by ensuring they get a minimum ownership percentage.', sort_order: 115 },
  { id: 'dc-startup-0116', deck_id: 'deck-startup-fundamentals', front: 'What is a discount rate on a convertible note?', back: 'A percentage discount (typically 15-25%) that early investors receive on the share price at the next funding round. If the Series A price is $1/share with a 20% discount, note holders convert at $0.80/share. It rewards early investors for taking on more risk.', sort_order: 116 },
  { id: 'dc-startup-0117', deck_id: 'deck-startup-fundamentals', front: 'What should a startup pitch deck include?', back: 'Key slides: Problem, Solution, Market Size (TAM/SAM/SOM), Product Demo, Business Model, Traction/Metrics, Competition, Team, Financial Projections, and The Ask (how much you are raising and how you will use the funds). Keep it to 10-15 slides maximum.', sort_order: 117 },
  { id: 'dc-startup-0118', deck_id: 'deck-startup-fundamentals', front: 'What is due diligence in startup fundraising?', back: 'The investigation process investors conduct before committing capital. It covers financials, legal documents, cap table, customer references, technology review, team background checks, and market analysis. Founders should maintain a clean data room to speed up the process.', sort_order: 118 },
  { id: 'dc-startup-0119', deck_id: 'deck-startup-fundamentals', front: 'What is burn rate?', back: 'The rate at which a startup spends cash, usually measured monthly. Gross burn is total monthly spending. Net burn is total spending minus revenue. If you spend $100K/month and earn $30K, your net burn is $70K/month. Monitoring burn rate is critical for survival.', sort_order: 119 },
  { id: 'dc-startup-0120', deck_id: 'deck-startup-fundamentals', front: 'What is runway?', back: 'The amount of time a startup can operate before running out of cash, calculated as cash on hand divided by monthly net burn rate. If you have $700K and burn $70K/month, you have 10 months of runway. Most startups should maintain at least 12-18 months of runway.', sort_order: 120 },
  { id: 'dc-startup-0121', deck_id: 'deck-startup-fundamentals', front: 'What is a break-even point?', back: 'The point at which total revenue equals total costs, meaning the business is no longer losing money. Reaching break-even is a significant milestone because it means the company can sustain itself without external funding. Calculate as Fixed Costs / (Price - Variable Cost per Unit).', sort_order: 121 },
  { id: 'dc-startup-0122', deck_id: 'deck-startup-fundamentals', front: 'What is a liquidation preference?', back: 'A term in venture deals that determines the order and amount investors get paid when a company is sold or liquidated. A 1x liquidation preference means the investor gets their money back before common shareholders receive anything. Participating preferences let investors double-dip.', sort_order: 122 },
  { id: 'dc-startup-0123', deck_id: 'deck-startup-fundamentals', front: 'What is anti-dilution protection?', back: 'A clause protecting investors from dilution if future rounds occur at a lower valuation (down round). The two common types are full ratchet (most investor-friendly, adjusts price to new lower price) and weighted average (more balanced, adjusts proportionally). Most deals use broad-based weighted average.', sort_order: 123 },
  { id: 'dc-startup-0124', deck_id: 'deck-startup-fundamentals', front: 'What is a down round?', back: 'A funding round where the company raises money at a lower valuation than the previous round. It signals the company has not met expectations and results in significant dilution for existing shareholders. Down rounds can trigger anti-dilution provisions and damage morale.', sort_order: 124 },
  { id: 'dc-startup-0125', deck_id: 'deck-startup-fundamentals', front: 'What is an equity split between co-founders?', back: 'The division of ownership among co-founders at the start. Common approaches: equal split for equal contribution, or adjusted based on idea origination, time commitment, and skills. Advisors recommend deciding early and using vesting schedules to protect against early departures.', sort_order: 125 },
  { id: 'dc-startup-0126', deck_id: 'deck-startup-fundamentals', front: 'What is Y Combinator (YC)?', back: 'The most prominent startup accelerator, founded in 2005. YC invests $500K for ~7% equity, provides three months of mentorship, and culminates in Demo Day where startups pitch to investors. Alumni include Airbnb, Stripe, Dropbox, and DoorDash.', sort_order: 126 },
  { id: 'dc-startup-0127', deck_id: 'deck-startup-fundamentals', front: 'What is a startup accelerator?', back: 'A fixed-term program (typically 3-6 months) that provides startups with mentorship, education, resources, and often seed funding in exchange for equity (usually 5-10%). Programs end with a demo day. Top accelerators include YC, Techstars, and 500 Global.', sort_order: 127 },
  { id: 'dc-startup-0128', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between an accelerator and an incubator?', back: 'Accelerators have fixed timelines (3-6 months), take equity, and focus on rapid growth for existing startups. Incubators provide longer-term support (1-5 years), may not take equity, and help nurture very early ideas into viable businesses. Accelerators are more intense and selective.', sort_order: 128 },
  { id: 'dc-startup-0129', deck_id: 'deck-startup-fundamentals', front: 'What is a financial model for a startup?', back: 'A spreadsheet projecting revenue, expenses, cash flow, and key metrics over 3-5 years. It includes assumptions about growth rate, pricing, headcount, and costs. Investors use it to assess viability and capital needs. Focus on the assumptions, not precise numbers.', sort_order: 129 },
  { id: 'dc-startup-0130', deck_id: 'deck-startup-fundamentals', front: 'What are revenue projections and how should startups approach them?', back: 'Forecasts of future revenue based on growth assumptions. Build them bottom-up using realistic inputs: number of customers you can acquire, conversion rates, average revenue per user, and churn. Avoid top-down projections like "we just need 1% of this giant market."', sort_order: 130 },
  { id: 'dc-startup-0131', deck_id: 'deck-startup-fundamentals', front: 'What is a pro rata right?', back: 'An investor right to participate in future funding rounds to maintain their ownership percentage. If an investor owns 10% and has pro rata rights, they can invest enough in the next round to keep their 10% stake. It protects investors from dilution.', sort_order: 131 },
  { id: 'dc-startup-0132', deck_id: 'deck-startup-fundamentals', front: 'What is a board of directors in a startup?', back: 'A group of individuals who oversee the company strategy, governance, and major decisions. Early-stage boards typically have 3-5 members: founders, investor representatives, and independent directors. The board hires/fires the CEO, approves budgets, and guides strategy.', sort_order: 132 },
  { id: 'dc-startup-0133', deck_id: 'deck-startup-fundamentals', front: 'What is a data room for fundraising?', back: 'A secure repository (often virtual) containing key documents investors review during due diligence: financials, legal documents, cap table, customer contracts, team info, IP documentation, and metrics. Having a well-organized data room speeds up the fundraising process.', sort_order: 133 },
  { id: 'dc-startup-0134', deck_id: 'deck-startup-fundamentals', front: 'What is preferred stock vs common stock?', back: 'Preferred stock is issued to investors and carries special rights: liquidation preference, anti-dilution protection, and voting rights. Common stock is held by founders and employees and has fewer protections. In a sale, preferred stockholders get paid first.', sort_order: 134 },
  { id: 'dc-startup-0135', deck_id: 'deck-startup-fundamentals', front: 'What is a bridge round?', back: 'A smaller funding round designed to bridge a company to its next major round. Often structured as convertible notes or SAFEs. Companies raise bridge rounds when they need more runway but are not ready for a full priced round. Can signal either momentum or distress.', sort_order: 135 },
  { id: 'dc-startup-0136', deck_id: 'deck-startup-fundamentals', front: 'What is a lead investor?', back: 'The primary investor in a funding round who negotiates the terms, sets the valuation, and often takes a board seat. Having a reputable lead investor signals quality to other investors and makes it easier to fill the rest of the round.', sort_order: 136 },
  { id: 'dc-startup-0137', deck_id: 'deck-startup-fundamentals', front: 'What is traction and how do investors evaluate it?', back: 'Evidence that your startup is gaining momentum. Key traction metrics include revenue growth, user growth, engagement metrics, retention rates, and notable partnerships or customers. Investors want to see consistent month-over-month growth and signs of product-market fit.', sort_order: 137 },
  { id: 'dc-startup-0138', deck_id: 'deck-startup-fundamentals', front: 'What is a startup valuation method at the early stage?', back: 'Early-stage valuations are more art than science. Methods include comparable company analysis, the Berkus method (assigning value to risk reduction factors), the scorecard method (adjusting based on team, market, product), and the venture capital method (working backward from expected exit).', sort_order: 138 },
  { id: 'dc-startup-0139', deck_id: 'deck-startup-fundamentals', front: 'What is the venture capital method of valuation?', back: 'Work backward from an expected exit value: if you expect a $100M exit in 5 years and the VC wants 10x return, the post-money valuation today should be $10M. For a $2M investment, the VC would own 20%. This method anchors valuation to investor return expectations.', sort_order: 139 },
  { id: 'dc-startup-0140', deck_id: 'deck-startup-fundamentals', front: 'What is the typical equity investors expect at each stage?', back: 'Pre-seed: 10-15% for $100K-$500K. Seed: 15-25% for $500K-$3M. Series A: 15-30% for $3-15M. These are rough ranges and vary by market, team, and traction. Founders should aim to retain 50%+ ownership through Series A for meaningful control and motivation.', sort_order: 140 },
  { id: 'dc-startup-0141', deck_id: 'deck-startup-fundamentals', front: 'What is a pitch deck narrative structure?', back: 'The most effective pitch decks tell a story: start with the problem (create urgency), present the solution (your product), prove the opportunity (market size), show traction (evidence it works), introduce the team (why you will win), and close with the ask (what you need to get to the next level).', sort_order: 141 },
  { id: 'dc-startup-0142', deck_id: 'deck-startup-fundamentals', front: 'What are common mistakes in startup fundraising?', back: 'Raising too much or too little, giving up too much equity too early, not having a clear use of funds, targeting wrong investors, poor storytelling, no clear metrics, and not creating urgency. Also: fundraising takes longer than expected — plan for 3-6 months.', sort_order: 142 },
  { id: 'dc-startup-0143', deck_id: 'deck-startup-fundamentals', front: 'What is investor-founder fit and why does it matter?', back: 'The alignment between a founder and investor on vision, expectations, communication style, and involvement level. Good investor-founder fit means the investor adds value beyond money through relevant expertise, connections, and constructive support. Bad fit can lead to conflicts and forced pivots.', sort_order: 143 },
  { id: 'dc-startup-0144', deck_id: 'deck-startup-fundamentals', front: 'What is a rolling close in fundraising?', back: 'Accepting investments as they come in rather than waiting for the entire round to be committed before closing. Common with SAFEs and convertible notes. It lets startups access capital faster, but requires careful management of different investor terms.', sort_order: 144 },
  { id: 'dc-startup-0145', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between revenue-based financing and equity financing?', back: 'Revenue-based financing provides capital in exchange for a percentage of future revenue until a fixed amount is repaid (typically 1.5-3x the investment). Unlike equity financing, founders retain full ownership. It works best for companies with predictable, recurring revenue.', sort_order: 145 },

  // === Marketing & Growth (146-195) ===
  { id: 'dc-startup-0146', deck_id: 'deck-startup-fundamentals', front: 'What is growth hacking?', back: 'A marketing approach focused on rapid experimentation across channels and product features to identify the most efficient ways to grow a business. Coined by Sean Ellis. It blends marketing, product development, and data analysis. Famous example: Hotmail adding "Get your free email" to every outgoing message.', sort_order: 146 },
  { id: 'dc-startup-0147', deck_id: 'deck-startup-fundamentals', front: 'What is the AARRR (Pirate Metrics) framework?', back: 'A funnel framework by Dave McClure: Acquisition (how users find you), Activation (first great experience), Retention (users come back), Revenue (users pay), Referral (users tell others). Focus on the weakest stage first — fixing a leaky bucket before pouring more water in.', sort_order: 147 },
  { id: 'dc-startup-0148', deck_id: 'deck-startup-fundamentals', front: 'What is SEO (Search Engine Optimization) for startups?', back: 'Optimizing your website to rank higher in search engine results for relevant queries. Includes technical SEO (site speed, mobile-friendly), on-page SEO (keywords, content quality), and off-page SEO (backlinks, domain authority). SEO is a long-term channel but provides sustainable free traffic.', sort_order: 148 },
  { id: 'dc-startup-0149', deck_id: 'deck-startup-fundamentals', front: 'What is content marketing?', back: 'Creating valuable, relevant content (blog posts, videos, guides, podcasts) to attract and engage your target audience. It builds trust and authority, improves SEO, and generates inbound leads. HubSpot built a $30B+ company largely through content marketing.', sort_order: 149 },
  { id: 'dc-startup-0150', deck_id: 'deck-startup-fundamentals', front: 'What is paid acquisition and when should startups use it?', back: 'Paying for advertising on platforms like Google Ads, Facebook/Meta Ads, or LinkedIn to acquire customers. Use it when you have validated your unit economics (LTV > 3x CAC) and want to scale predictably. Start with small budgets, test multiple creatives, and measure ROI rigorously.', sort_order: 150 },
  { id: 'dc-startup-0151', deck_id: 'deck-startup-fundamentals', front: 'What is a conversion funnel?', back: 'The journey a potential customer takes from first awareness to becoming a paying customer. Each stage has a conversion rate. For example: 1000 visitors, 100 sign up (10%), 30 activate (30%), 10 subscribe (33%). Improving any stage has a multiplicative effect on revenue.', sort_order: 151 },
  { id: 'dc-startup-0152', deck_id: 'deck-startup-fundamentals', front: 'What is a referral program and how should startups design one?', back: 'A structured system that rewards existing users for bringing in new users. Effective programs offer two-sided incentives (both referrer and referee get value). Dropbox grew 3900% in 15 months by offering extra storage for referrals. The reward should align with your product value.', sort_order: 152 },
  { id: 'dc-startup-0153', deck_id: 'deck-startup-fundamentals', front: 'What is a viral loop?', back: 'A mechanism where each new user naturally invites or exposes other potential users to the product as part of normal usage. The viral coefficient (K-factor) is the number of new users each existing user generates. If K > 1, growth is exponential. Examples: shared documents, social posts.', sort_order: 153 },
  { id: 'dc-startup-0154', deck_id: 'deck-startup-fundamentals', front: 'What is the viral coefficient (K-factor)?', back: 'A metric measuring viral growth: K = (invitations sent per user) x (conversion rate of those invitations). If K > 1, each user brings in more than one new user, creating exponential growth. Even K values below 1 amplify other acquisition channels and reduce effective CAC.', sort_order: 154 },
  { id: 'dc-startup-0155', deck_id: 'deck-startup-fundamentals', front: 'What is email marketing for startups?', back: 'Using email to nurture leads, onboard users, and retain customers. Key tactics include welcome sequences, educational drip campaigns, product updates, and re-engagement emails. Email has one of the highest ROI among marketing channels. Segment your list and personalize content.', sort_order: 155 },
  { id: 'dc-startup-0156', deck_id: 'deck-startup-fundamentals', front: 'What is a drip campaign?', back: 'An automated sequence of emails sent over time based on triggers (sign-up, action, inactivity). Each email builds on the previous one to guide users toward a goal. Example: Day 1 welcome, Day 3 feature highlight, Day 7 case study, Day 14 upgrade offer.', sort_order: 156 },
  { id: 'dc-startup-0157', deck_id: 'deck-startup-fundamentals', front: 'What is A/B testing?', back: 'Comparing two versions of a webpage, email, or feature to see which performs better. Show version A to half your audience and version B to the other half, then measure which has better conversion. Test one variable at a time and ensure statistical significance before drawing conclusions.', sort_order: 157 },
  { id: 'dc-startup-0158', deck_id: 'deck-startup-fundamentals', front: 'What is landing page optimization?', back: 'Improving a landing page to maximize conversions. Key elements: clear headline, compelling value proposition, social proof (testimonials, logos), strong call to action, minimal distractions, and fast load time. A/B test headlines, images, and CTAs to find the highest converting combination.', sort_order: 158 },
  { id: 'dc-startup-0159', deck_id: 'deck-startup-fundamentals', front: 'What is a customer persona?', back: 'A fictional, detailed representation of your ideal customer based on real data and research. Includes demographics, goals, frustrations, behavior patterns, and preferred channels. Personas help teams make consistent product and marketing decisions aligned with actual user needs.', sort_order: 159 },
  { id: 'dc-startup-0160', deck_id: 'deck-startup-fundamentals', front: 'What is ICP (Ideal Customer Profile)?', back: 'A description of the type of company or individual that would benefit most from your product. For B2B, it includes company size, industry, budget, and pain points. For B2C, it covers demographics, behaviors, and needs. Focusing on your ICP improves conversion rates and reduces wasted spend.', sort_order: 160 },
  { id: 'dc-startup-0161', deck_id: 'deck-startup-fundamentals', front: 'How can startups build a brand on a limited budget?', back: 'Focus on consistency across all touchpoints: name, logo, voice, colors, and messaging. Tell an authentic founder story. Engage actively on social media. Create valuable content. Build community around your mission. Leverage PR and partnerships. Strong brands are built through trust, not ad spend.', sort_order: 161 },
  { id: 'dc-startup-0162', deck_id: 'deck-startup-fundamentals', front: 'How should startups approach a Product Hunt launch?', back: 'Prepare in advance: build an email list, create compelling visuals, write a clear tagline, and line up supporters to upvote and comment on launch day. Launch on Tuesday-Thursday for best visibility. Engage actively in comments. A successful launch can drive thousands of sign-ups in one day.', sort_order: 162 },
  { id: 'dc-startup-0163', deck_id: 'deck-startup-fundamentals', front: 'What is social media marketing for startups?', back: 'Using platforms like Twitter/X, LinkedIn, Instagram, and TikTok to build brand awareness, engage with customers, and drive traffic. Choose 1-2 platforms where your target audience is most active. Consistency matters more than frequency. Share value, not just promotions.', sort_order: 163 },
  { id: 'dc-startup-0164', deck_id: 'deck-startup-fundamentals', front: 'What is a go-to-market (GTM) strategy?', back: 'A plan for how you will bring your product to market and acquire customers. It covers target audience, value proposition, pricing, distribution channels, marketing strategy, and sales process. A strong GTM strategy aligns product, marketing, and sales around the same customer segments.', sort_order: 164 },
  { id: 'dc-startup-0165', deck_id: 'deck-startup-fundamentals', front: 'What is inbound vs outbound marketing?', back: 'Inbound attracts customers through valuable content, SEO, and social media — customers come to you. Outbound reaches out to prospects through cold emails, calls, ads, and events — you go to customers. Most startups benefit from a mix, weighted by their business model (B2B tends outbound, B2C tends inbound).', sort_order: 165 },
  { id: 'dc-startup-0166', deck_id: 'deck-startup-fundamentals', front: 'What is customer acquisition through partnerships?', back: 'Collaborating with complementary businesses to access their customer base. Types include co-marketing (joint content), integrations (connecting products), affiliate programs (commission-based referrals), and distribution partnerships. Choose partners whose customers match your ICP.', sort_order: 166 },
  { id: 'dc-startup-0167', deck_id: 'deck-startup-fundamentals', front: 'What is PR (Public Relations) for startups?', back: 'Earning media coverage through press releases, journalist relationships, and compelling stories. Effective startup PR focuses on a unique founder story, innovative technology, impressive traction, or timely industry trends. Free coverage in top publications can drive significant traffic and credibility.', sort_order: 167 },
  { id: 'dc-startup-0168', deck_id: 'deck-startup-fundamentals', front: 'What is CPC (Cost Per Click) in paid advertising?', back: 'The amount you pay each time someone clicks on your ad. Calculated as total ad spend divided by total clicks. Varies widely by industry and platform ($0.50-$50+). Use CPC along with conversion rate to calculate your cost per acquisition and determine profitability.', sort_order: 168 },
  { id: 'dc-startup-0169', deck_id: 'deck-startup-fundamentals', front: 'What is CPA (Cost Per Acquisition) in marketing?', back: 'The cost to acquire one paying customer through a specific marketing channel. Calculated as total channel spend divided by number of customers acquired. CPA must be lower than LTV for the channel to be profitable. Compare CPA across channels to optimize your marketing budget.', sort_order: 169 },
  { id: 'dc-startup-0170', deck_id: 'deck-startup-fundamentals', front: 'What is organic growth vs paid growth?', back: 'Organic growth comes from word-of-mouth, SEO, content, and product virality — no direct cost per user. Paid growth comes from advertising and sponsorships — predictable but costs money. The best startups build strong organic growth engines first, then amplify with paid channels.', sort_order: 170 },
  { id: 'dc-startup-0171', deck_id: 'deck-startup-fundamentals', front: 'What is community-led growth?', back: 'A strategy where a community of passionate users drives product adoption, feedback, and advocacy. Examples: Notion, Figma, and dbt all built strong communities that created content, answered questions, and attracted new users. Requires genuine investment in community value, not just marketing.', sort_order: 171 },
  { id: 'dc-startup-0172', deck_id: 'deck-startup-fundamentals', front: 'What is a launch strategy for a new startup?', back: 'A coordinated plan to maximize impact when releasing your product. Common elements: build anticipation with a waitlist, launch on Product Hunt and Hacker News, send a press release, activate your network for social sharing, offer limited-time incentives, and capture and respond to all feedback.', sort_order: 172 },
  { id: 'dc-startup-0173', deck_id: 'deck-startup-fundamentals', front: 'What is the 80/20 rule (Pareto Principle) applied to marketing?', back: 'Roughly 80% of your results come from 20% of your efforts. In marketing, this means a few channels drive most of your growth. Identify your top-performing channels and double down on them rather than spreading resources thin across many channels.', sort_order: 173 },
  { id: 'dc-startup-0174', deck_id: 'deck-startup-fundamentals', front: 'What is retention marketing?', back: 'Marketing efforts focused on keeping existing customers engaged and reducing churn. Tactics include personalized emails, in-app messaging, loyalty programs, customer success outreach, and product education. Retaining a customer is 5-25x cheaper than acquiring a new one.', sort_order: 174 },
  { id: 'dc-startup-0175', deck_id: 'deck-startup-fundamentals', front: 'What is a marketing funnel vs a flywheel?', back: 'A funnel is a linear model: awareness, consideration, decision. The flywheel (popularized by HubSpot) is a circular model where happy customers drive referrals and growth, creating self-sustaining momentum. The flywheel better represents how modern growth-oriented companies actually grow.', sort_order: 175 },
  { id: 'dc-startup-0176', deck_id: 'deck-startup-fundamentals', front: 'What is activation rate and why does it matter?', back: 'The percentage of signed-up users who complete a key action that indicates they have experienced your core value (e.g., completing onboarding, sending first message, making first project). Low activation is a sign of poor onboarding. Improving it is often the highest-leverage growth fix.', sort_order: 176 },
  { id: 'dc-startup-0177', deck_id: 'deck-startup-fundamentals', front: 'What is a channel-market fit?', back: 'Finding the right acquisition channel for your specific market and product type. Not all channels work for all businesses. B2B SaaS might work best with content marketing and LinkedIn; a consumer app might need TikTok or influencers. Test channels systematically before committing.', sort_order: 177 },
  { id: 'dc-startup-0178', deck_id: 'deck-startup-fundamentals', front: 'What is influencer marketing for startups?', back: 'Partnering with people who have large, engaged followings in your target market. Micro-influencers (1K-100K followers) often have higher engagement rates and lower costs than macro-influencers. Measure ROI through tracking links, promo codes, and attributed sign-ups or sales.', sort_order: 178 },
  { id: 'dc-startup-0179', deck_id: 'deck-startup-fundamentals', front: 'What is a waitlist strategy for pre-launch?', back: 'Collecting email addresses from interested potential users before your product is ready. Benefits: validates demand, builds an audience for launch day, and creates exclusivity. Enhance it with referral bonuses (move up the list by sharing), progress updates, and early access for top referrers.', sort_order: 179 },
  { id: 'dc-startup-0180', deck_id: 'deck-startup-fundamentals', front: 'What is customer segmentation?', back: 'Dividing your customer base into groups based on shared characteristics like behavior, demographics, or needs. Segmentation enables personalized marketing, better targeting, and differentiated pricing. Example: Slack segments by team size to tailor messaging and pricing tiers.', sort_order: 180 },
  { id: 'dc-startup-0181', deck_id: 'deck-startup-fundamentals', front: 'What is a lead magnet?', back: 'A free resource (ebook, template, tool, webinar) offered in exchange for a visitor email address. It starts the relationship and lets you nurture the lead through email marketing. The best lead magnets solve a specific problem related to your paid product.', sort_order: 181 },
  { id: 'dc-startup-0182', deck_id: 'deck-startup-fundamentals', front: 'What is NPS (Net Promoter Score)?', back: 'A metric that measures customer loyalty by asking: "How likely are you to recommend this product to a friend?" (0-10 scale). Promoters (9-10) minus Detractors (0-6) = NPS. Scores above 50 are excellent. NPS correlates with organic growth through word-of-mouth.', sort_order: 182 },
  { id: 'dc-startup-0183', deck_id: 'deck-startup-fundamentals', front: 'What is the Hacker News launch strategy?', back: 'Posting a Show HN on news.ycombinator.com to reach a technical, early-adopter audience. Write a clear title, provide a genuine demo, and be responsive in comments. A front-page post can drive 10K-50K visitors in a day. Best for developer tools, SaaS, and technical products.', sort_order: 183 },
  { id: 'dc-startup-0184', deck_id: 'deck-startup-fundamentals', front: 'What is a growth experiment?', back: 'A structured test of a hypothesis about what will drive growth. Define the hypothesis, set a success metric, run the test for a fixed period, and analyze results. Examples: testing a new CTA button, trying a different ad audience, or changing onboarding steps. Run many small experiments to find winners.', sort_order: 184 },
  { id: 'dc-startup-0185', deck_id: 'deck-startup-fundamentals', front: 'What is social proof and how do startups use it?', back: 'The psychological phenomenon where people follow the actions and opinions of others. Startups leverage it through customer testimonials, user counts, logos of well-known clients, star ratings, press mentions, and case studies. Social proof is one of the most effective conversion tools.', sort_order: 185 },
  { id: 'dc-startup-0186', deck_id: 'deck-startup-fundamentals', front: 'What is a call to action (CTA)?', back: 'A prompt that tells the visitor exactly what to do next: "Start Free Trial," "Sign Up Now," "Get Started." Effective CTAs are specific, action-oriented, create urgency, and stand out visually. Test different CTA text, color, and placement to optimize conversion rates.', sort_order: 186 },
  { id: 'dc-startup-0187', deck_id: 'deck-startup-fundamentals', front: 'What is SEO keyword research for startups?', back: 'The process of finding search terms your target customers use and creating content around them. Focus on long-tail keywords with lower competition and higher intent. Tools like Ahrefs, SEMrush, and Google Keyword Planner help identify opportunities. Prioritize keywords aligned with buyer intent.', sort_order: 187 },
  { id: 'dc-startup-0188', deck_id: 'deck-startup-fundamentals', front: 'What is a customer success function?', back: 'A team or role dedicated to ensuring customers achieve their desired outcomes using your product. Unlike support (reactive), customer success is proactive — reaching out to help users adopt features, expand usage, and renew. Critical for reducing churn in SaaS businesses.', sort_order: 188 },
  { id: 'dc-startup-0189', deck_id: 'deck-startup-fundamentals', front: 'What is a freemium conversion strategy?', back: 'Tactics to move free users to paid plans. Best practices: clearly demonstrate the value of premium features, use usage limits that trigger when users are engaged, send targeted upgrade prompts based on behavior, and offer time-limited trials of premium features.', sort_order: 189 },
  { id: 'dc-startup-0190', deck_id: 'deck-startup-fundamentals', front: 'What is attribution in marketing?', back: 'Determining which marketing channels and touchpoints deserve credit for a conversion. Models include first-touch (credit to the first interaction), last-touch (credit to the final interaction), and multi-touch (credit distributed across interactions). Proper attribution helps optimize marketing spend.', sort_order: 190 },
  { id: 'dc-startup-0191', deck_id: 'deck-startup-fundamentals', front: 'What is a product-qualified lead (PQL)?', back: 'A lead who has used your product (usually through a free trial or freemium tier) and demonstrated behavior indicating they are likely to become a paying customer. PQLs convert at much higher rates than marketing-qualified leads because they have already experienced value.', sort_order: 191 },
  { id: 'dc-startup-0192', deck_id: 'deck-startup-fundamentals', front: 'What is cold outreach and when is it effective?', back: 'Contacting potential customers who have not expressed interest, typically via email or LinkedIn. Effective for B2B startups targeting specific companies. Keys to success: personalize each message, lead with value not features, keep it short, and follow up persistently but respectfully.', sort_order: 192 },
  { id: 'dc-startup-0193', deck_id: 'deck-startup-fundamentals', front: 'What is a marketing channel strategy for early startups?', back: 'Test 2-3 channels at a time with small budgets, measure results rigorously, and double down on what works. The Bullseye Framework by Gabriel Weinberg suggests brainstorming all 19 traction channels, testing the most promising three, and focusing on the single best performer.', sort_order: 193 },
  { id: 'dc-startup-0194', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between brand marketing and performance marketing?', back: 'Brand marketing builds long-term awareness, trust, and emotional connection (harder to measure directly). Performance marketing drives immediate, measurable actions like clicks, sign-ups, or purchases. Early-stage startups usually focus on performance marketing but should build brand over time.', sort_order: 194 },
  { id: 'dc-startup-0195', deck_id: 'deck-startup-fundamentals', front: 'What is a customer feedback loop in growth?', back: 'A process where customer feedback directly informs product improvements, which then increase satisfaction and drive more referrals. The tighter this loop, the faster you improve. Collect feedback through surveys, support tickets, interviews, and usage analytics. Close the loop by communicating changes back.', sort_order: 195 },

  // === Legal & Operations (196-220) ===
  { id: 'dc-startup-0196', deck_id: 'deck-startup-fundamentals', front: 'What is an LLC (Limited Liability Company)?', back: 'A business structure that provides personal liability protection while offering tax flexibility. Owners (members) are not personally liable for business debts. LLCs can be taxed as sole proprietorships, partnerships, or corporations. Popular for small businesses but less common for VC-backed startups.', sort_order: 196 },
  { id: 'dc-startup-0197', deck_id: 'deck-startup-fundamentals', front: 'What is a C-Corp and why do startups choose it?', back: 'A type of corporation that is a separate legal entity from its owners. C-Corps can issue multiple classes of stock (common and preferred), which is required for venture capital investment. Most VC-backed startups incorporate as Delaware C-Corps due to well-established corporate law.', sort_order: 197 },
  { id: 'dc-startup-0198', deck_id: 'deck-startup-fundamentals', front: 'What is an S-Corp?', back: 'A tax election that allows a corporation to pass income, losses, and deductions through to shareholders, avoiding double taxation. Limited to 100 shareholders, all of whom must be US citizens/residents. Not suitable for VC-backed startups because it cannot issue preferred stock to investors.', sort_order: 198 },
  { id: 'dc-startup-0199', deck_id: 'deck-startup-fundamentals', front: 'Why do many startups incorporate in Delaware?', back: 'Delaware has the most developed body of corporate law, a specialized business court (Court of Chancery), and predictable legal precedents. Investors and lawyers are familiar with Delaware law, which reduces legal costs and complexity. Most VC-backed startups incorporate there regardless of where they operate.', sort_order: 199 },
  { id: 'dc-startup-0200', deck_id: 'deck-startup-fundamentals', front: 'What is a patent and when should startups file one?', back: 'A government-granted right that excludes others from making, using, or selling an invention for typically 20 years. Filing is expensive ($10K-$30K+) and slow (2-4 years). Startups should file when they have a truly novel, non-obvious invention that is core to their competitive advantage.', sort_order: 200 },
  { id: 'dc-startup-0201', deck_id: 'deck-startup-fundamentals', front: 'What is a trademark?', back: 'Legal protection for brand identifiers like names, logos, slogans, and sounds. Registration with the USPTO provides nationwide protection and the right to sue for infringement. Startups should trademark their name and logo early to prevent competitors from using similar branding.', sort_order: 201 },
  { id: 'dc-startup-0202', deck_id: 'deck-startup-fundamentals', front: 'What is copyright in the context of startups?', back: 'Legal protection for original creative works including software code, written content, designs, and media. Copyright is automatic upon creation but registration provides stronger legal standing. Startups should ensure they own copyrights to all code and content created by employees and contractors.', sort_order: 202 },
  { id: 'dc-startup-0203', deck_id: 'deck-startup-fundamentals', front: 'What is a trade secret?', back: 'Confidential business information that provides a competitive advantage, such as algorithms, customer lists, or manufacturing processes. Unlike patents, trade secrets have no expiration but lose protection if disclosed. Protect them with NDAs, access controls, and employee agreements.', sort_order: 203 },
  { id: 'dc-startup-0204', deck_id: 'deck-startup-fundamentals', front: 'What should a co-founder agreement include?', back: 'Key elements: equity split, vesting schedules, roles and responsibilities, decision-making process, IP assignment, salary expectations, what happens if a co-founder leaves, dispute resolution, and non-compete clauses. Put it in writing before writing any code — even with your best friend.', sort_order: 204 },
  { id: 'dc-startup-0205', deck_id: 'deck-startup-fundamentals', front: 'What is a standard vesting schedule for founders?', back: 'The most common is 4-year vesting with a 1-year cliff. The cliff means no equity vests until the first anniversary, then 25% vests at once. After the cliff, the remaining 75% vests monthly over 3 years. This protects the company if a co-founder leaves early.', sort_order: 205 },
  { id: 'dc-startup-0206', deck_id: 'deck-startup-fundamentals', front: 'What is a 1-year cliff in vesting?', back: 'A period during which no equity vests. If a founder or employee leaves before the cliff date (typically 1 year), they get zero equity. After the cliff, a large chunk vests immediately (usually 25%), and the rest vests gradually. It protects against people joining briefly and walking away with equity.', sort_order: 206 },
  { id: 'dc-startup-0207', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between a contractor and an employee?', back: 'Employees work under company direction, use company tools, and receive benefits. Contractors work independently, set their own hours, and provide their own tools. Misclassifying employees as contractors can result in significant legal penalties and back taxes. The IRS uses a multi-factor test.', sort_order: 207 },
  { id: 'dc-startup-0208', deck_id: 'deck-startup-fundamentals', front: 'Why do startups need Terms of Service?', back: 'Terms of Service define the legal agreement between the company and its users. They set expectations for acceptable use, limit liability, establish dispute resolution procedures, and protect intellectual property. Having clear terms reduces legal risk and is required for most app stores.', sort_order: 208 },
  { id: 'dc-startup-0209', deck_id: 'deck-startup-fundamentals', front: 'Why do startups need a Privacy Policy?', back: 'A Privacy Policy discloses how you collect, use, store, and share user data. It is legally required in most jurisdictions if you collect any personal data. Required by GDPR, CCPA, and app stores. Lack of a privacy policy can result in fines, lawsuits, and loss of user trust.', sort_order: 209 },
  { id: 'dc-startup-0210', deck_id: 'deck-startup-fundamentals', front: 'What is GDPR and how does it affect startups?', back: 'The General Data Protection Regulation is an EU law governing personal data collection and processing. It requires explicit user consent, data minimization, the right to be forgotten, and breach notification within 72 hours. Applies to any company serving EU residents, regardless of location. Fines can reach 4% of global revenue.', sort_order: 210 },
  { id: 'dc-startup-0211', deck_id: 'deck-startup-fundamentals', front: 'What is an IP (Intellectual Property) assignment agreement?', back: 'A legal document transferring ownership of intellectual property created by founders, employees, or contractors to the company. Without it, creators may retain IP rights. Every person who writes code, creates designs, or develops ideas for the startup should sign one.', sort_order: 211 },
  { id: 'dc-startup-0212', deck_id: 'deck-startup-fundamentals', front: 'What is a Non-Disclosure Agreement (NDA)?', back: 'A legal contract that prevents parties from sharing confidential information. Startups use NDAs with employees, contractors, and sometimes partners. Most VCs will not sign NDAs because they see many similar pitches. Use NDAs selectively — overusing them signals inexperience.', sort_order: 212 },
  { id: 'dc-startup-0213', deck_id: 'deck-startup-fundamentals', front: 'What is a non-compete agreement?', back: 'A contract clause preventing employees or founders from working for competitors or starting competing businesses for a specified period after leaving. Enforceability varies widely by jurisdiction — California generally does not enforce them. Some states have banned them entirely for employees.', sort_order: 213 },
  { id: 'dc-startup-0214', deck_id: 'deck-startup-fundamentals', front: 'What is 83(b) election and why should founders file it?', back: 'A tax filing that allows founders to pay tax on restricted stock at its current (low) value rather than when it vests at a potentially much higher value. Must be filed within 30 days of receiving stock. Missing the deadline cannot be reversed and can result in enormous tax bills later.', sort_order: 214 },
  { id: 'dc-startup-0215', deck_id: 'deck-startup-fundamentals', front: 'What are the legal requirements to hire employees?', back: 'Key requirements include obtaining an EIN, setting up payroll and tax withholding, verifying employment eligibility (I-9 form), providing workers compensation insurance, complying with wage and hour laws, and following anti-discrimination regulations. Use payroll services like Gusto or Rippling.', sort_order: 215 },
  { id: 'dc-startup-0216', deck_id: 'deck-startup-fundamentals', front: 'What is CCPA and how does it affect startups?', back: 'The California Consumer Privacy Act gives California residents the right to know what personal data is collected, request deletion, and opt out of data sales. It applies to businesses meeting certain revenue or data thresholds. Similar to GDPR but with some key differences in scope and enforcement.', sort_order: 216 },
  { id: 'dc-startup-0217', deck_id: 'deck-startup-fundamentals', front: 'What is a SaaS service-level agreement (SLA)?', back: 'A contract defining the level of service a customer can expect, including uptime guarantees (e.g., 99.9%), response times for support, and remedies if the provider fails to meet commitments. Enterprise customers often require SLAs before signing. Breaching an SLA can trigger service credits or refunds.', sort_order: 217 },
  { id: 'dc-startup-0218', deck_id: 'deck-startup-fundamentals', front: 'What is corporate governance for startups?', back: 'The system of rules and practices governing how a company is directed and controlled. Includes board structure, shareholder rights, meeting protocols, and decision-making processes. Good governance builds investor confidence and prevents conflicts. Start simple and formalize as you grow.', sort_order: 218 },
  { id: 'dc-startup-0219', deck_id: 'deck-startup-fundamentals', front: 'What is a data processing agreement (DPA)?', back: 'A legally binding contract between a data controller and data processor that outlines how personal data will be handled. Required under GDPR when you share user data with third-party services. It specifies data security measures, breach notification procedures, and subprocessor terms.', sort_order: 219 },
  { id: 'dc-startup-0220', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between incorporation and registration?', back: 'Incorporation creates a new legal entity (corporation or LLC) with its own rights and liabilities. Registration (foreign qualification) is notifying a state that your already-incorporated company will do business there. You incorporate once but may need to register in multiple states where you operate.', sort_order: 220 },

  // === Team & Culture (221-240) ===
  { id: 'dc-startup-0221', deck_id: 'deck-startup-fundamentals', front: 'How should startups approach hiring their first employees?', back: 'Hire generalists who are adaptable and self-directed, not specialists. Look for people who thrive in ambiguity and wear multiple hats. Prioritize culture fit and passion for the mission. Offer equity to compensate for below-market salaries. First hires define your culture — choose carefully.', sort_order: 221 },
  { id: 'dc-startup-0222', deck_id: 'deck-startup-fundamentals', front: 'What is equity compensation for startup employees?', back: 'Offering stock options or restricted stock as part of compensation, letting employees share in the company upside. Typical employee option pools are 10-20% of total shares. Standard vesting is 4 years with a 1-year cliff. Equity aligns employee and company interests.', sort_order: 222 },
  { id: 'dc-startup-0223', deck_id: 'deck-startup-fundamentals', front: 'What is an ESOP (Employee Stock Option Pool)?', back: 'A reserved pool of shares set aside for current and future employee stock option grants, typically 10-20% of total shares. Investors usually require creating an ESOP before investment, and it comes from the pre-money valuation (diluting founders, not investors).', sort_order: 223 },
  { id: 'dc-startup-0224', deck_id: 'deck-startup-fundamentals', front: 'What is the difference between stock options and restricted stock?', back: 'Stock options give the right to buy shares at a set price (strike price) in the future. Restricted stock is actual ownership of shares, subject to vesting. Founders typically receive restricted stock (file 83(b) election). Employees typically receive stock options.', sort_order: 224 },
  { id: 'dc-startup-0225', deck_id: 'deck-startup-fundamentals', front: 'How do you build company culture from day one?', back: 'Define your core values early and hire people who embody them. Lead by example — culture flows from founder behavior. Create rituals (team lunches, retrospectives, celebrations). Document your culture and share it openly. Culture is not about perks — it is about how decisions are made and how people treat each other.', sort_order: 225 },
  { id: 'dc-startup-0226', deck_id: 'deck-startup-fundamentals', front: 'What are the pros and cons of remote vs in-person startup teams?', back: 'Remote: access to global talent, lower overhead, flexibility, but harder to build culture and communicate quickly. In-person: faster collaboration, stronger bonds, easier onboarding, but limited talent pool and higher costs. Many startups succeed with hybrid models — remote-first with periodic in-person meetups.', sort_order: 226 },
  { id: 'dc-startup-0227', deck_id: 'deck-startup-fundamentals', front: 'What leadership styles work best for startup founders?', back: 'Servant leadership (removing obstacles for the team), transformational leadership (inspiring through vision), and situational leadership (adapting style to context) all work well. The best founders combine clear vision with humility, decisiveness with openness to feedback, and urgency with empathy.', sort_order: 227 },
  { id: 'dc-startup-0228', deck_id: 'deck-startup-fundamentals', front: 'How do you manage co-founder relationships?', back: 'Set clear roles and decision-making authority upfront. Communicate regularly and honestly. Address conflicts early — they do not resolve themselves. Have a formal co-founder agreement. Schedule regular check-ins to discuss strategy, concerns, and personal well-being. Co-founder breakups are a top reason startups fail.', sort_order: 228 },
  { id: 'dc-startup-0229', deck_id: 'deck-startup-fundamentals', front: 'What is a startup advisory board?', back: 'A group of experienced individuals who provide strategic advice, introductions, and credibility. Unlike board directors, advisors have no legal authority or fiduciary duty. Compensate with 0.25-1% equity vesting over 2 years. Choose advisors who fill specific knowledge gaps and actively open doors.', sort_order: 229 },
  { id: 'dc-startup-0230', deck_id: 'deck-startup-fundamentals', front: 'What is the role of a mentor for startup founders?', back: 'A mentor provides guidance based on their own experience, acts as a sounding board for difficult decisions, and helps founders avoid common mistakes. The best mentoring relationships are specific (focused on particular challenges) and ongoing. Look for mentors who have built companies in your industry.', sort_order: 230 },
  { id: 'dc-startup-0231', deck_id: 'deck-startup-fundamentals', front: 'How should startups approach their first sales hire?', back: 'Founders should sell the product themselves first to understand the process and customer objections. Only hire a salesperson when you have a repeatable sales process. Look for someone who has sold to your target market before and is comfortable with ambiguity. Give them a ramp period of 3-6 months.', sort_order: 231 },
  { id: 'dc-startup-0232', deck_id: 'deck-startup-fundamentals', front: 'What is founder burnout and how do you prevent it?', back: 'Physical and emotional exhaustion from the sustained intensity of building a startup. Prevent it by setting boundaries, maintaining relationships outside work, exercising regularly, and delegating tasks. Recognize that working 80+ hours per week is not sustainable and leads to worse decisions.', sort_order: 232 },
  { id: 'dc-startup-0233', deck_id: 'deck-startup-fundamentals', front: 'What is the ideal founding team composition?', back: 'A strong founding team typically has complementary skills: a builder (technical), a seller (business/sales), and optionally a designer (product/UX). Shared values and work ethic matter more than identical backgrounds. Two to three co-founders is ideal — solo founders face higher burnout risk.', sort_order: 233 },
  { id: 'dc-startup-0234', deck_id: 'deck-startup-fundamentals', front: 'What are OKRs (Objectives and Key Results)?', back: 'A goal-setting framework popularized by Google. Objectives are qualitative goals (what you want to achieve). Key Results are quantitative metrics that measure progress (how you know you achieved it). Example: Objective — Improve onboarding. KR1 — Increase activation rate from 30% to 50%.', sort_order: 234 },
  { id: 'dc-startup-0235', deck_id: 'deck-startup-fundamentals', front: 'How do startups create effective onboarding for new hires?', back: 'Prepare a 30-60-90 day plan with clear expectations. Assign a buddy or mentor. Provide documentation on tools, processes, and company context. Schedule meetings with key team members. Give a small, quick-win project in the first week. Good onboarding dramatically improves retention and productivity.', sort_order: 235 },
  { id: 'dc-startup-0236', deck_id: 'deck-startup-fundamentals', front: 'What is psychological safety in a startup team?', back: 'An environment where team members feel safe to take risks, voice opinions, ask questions, and admit mistakes without fear of punishment. Google Project Aristotle found it was the number one factor in high-performing teams. Founders create it by responding to vulnerability with support, not criticism.', sort_order: 236 },
  { id: 'dc-startup-0237', deck_id: 'deck-startup-fundamentals', front: 'When should a startup make its first executive hire?', back: 'Hire executives (VP of Engineering, VP of Sales) when the function they lead becomes too complex for the founder to manage effectively — typically after finding product-market fit and entering the scaling phase. Hiring too early wastes runway; too late creates bottlenecks and burnout.', sort_order: 237 },
  { id: 'dc-startup-0238', deck_id: 'deck-startup-fundamentals', front: 'What is a cultural interview and why do startups use them?', back: 'A dedicated interview focused on assessing whether a candidate aligns with the company values and working style, separate from the technical interview. It evaluates communication, collaboration, adaptability, and mindset. Poor culture fit is a leading cause of early employee departures.', sort_order: 238 },
  { id: 'dc-startup-0239', deck_id: 'deck-startup-fundamentals', front: 'What is a flat organizational structure in startups?', back: 'A structure with few or no management layers between staff and leadership. Common in early-stage startups because it enables fast decision-making and direct communication. As companies grow beyond 15-20 people, some structure and middle management usually becomes necessary to avoid chaos.', sort_order: 239 },
  { id: 'dc-startup-0240', deck_id: 'deck-startup-fundamentals', front: 'How should founders handle firing underperforming employees?', back: 'Act quickly once you have given clear feedback and a reasonable improvement period. Document performance issues. Be direct, compassionate, and brief in the conversation. Offer a severance package if possible. Delaying a necessary termination hurts the team, the company, and the individual.', sort_order: 240 },

  // === Scaling & Advanced (241-250) ===
  { id: 'dc-startup-0241', deck_id: 'deck-startup-fundamentals', front: 'When should a startup begin scaling?', back: 'Scale only after achieving product-market fit, proven unit economics, and a repeatable acquisition process. Premature scaling (hiring, spending on marketing, expanding before these are in place) is the number one cause of startup death. Growth without retention is just expensive churn.', sort_order: 241 },
  { id: 'dc-startup-0242', deck_id: 'deck-startup-fundamentals', front: 'How do startups approach international expansion?', back: 'Research local regulations, cultural differences, payment methods, and competition. Start with one market at a time. Consider localization (language, currency, support hours). Test demand with lightweight approaches (translated landing pages, local ads) before committing full resources.', sort_order: 242 },
  { id: 'dc-startup-0243', deck_id: 'deck-startup-fundamentals', front: 'When should a startup pivot vs persevere?', back: 'Pivot when data consistently shows your current approach is not working despite multiple iterations, or when you discover a bigger opportunity adjacent to your current model. Persevere when metrics are trending in the right direction, even if slowly. Eric Ries suggests pivoting on strategy while keeping the vision.', sort_order: 243 },
  { id: 'dc-startup-0244', deck_id: 'deck-startup-fundamentals', front: 'What are common types of pivots?', back: 'Zoom-in pivot (a feature becomes the product), zoom-out pivot (the product becomes a feature of something larger), customer segment pivot (targeting different users), value capture pivot (changing the revenue model), channel pivot (changing distribution), and technology pivot (using a different technology).', sort_order: 244 },
  { id: 'dc-startup-0245', deck_id: 'deck-startup-fundamentals', front: 'What are exit strategies for startup founders?', back: 'IPO (going public on a stock exchange), acquisition (being bought by a larger company), merger (combining with another company), management buyout, or acqui-hire (acquired primarily for the team). Most successful exits are acquisitions. Plan your preferred exit early as it influences strategy.', sort_order: 245 },
  { id: 'dc-startup-0246', deck_id: 'deck-startup-fundamentals', front: 'What is an IPO (Initial Public Offering)?', back: 'The first time a company sells shares to the public on a stock exchange. It provides liquidity for founders and investors, raises large amounts of capital, and increases public visibility. Requirements include audited financials, regulatory compliance (SEC), and significant legal costs.', sort_order: 246 },
  { id: 'dc-startup-0247', deck_id: 'deck-startup-fundamentals', front: 'What are key startup metrics and KPIs investors track?', back: 'Revenue growth rate (month-over-month), gross margin, net revenue retention, CAC and LTV, burn rate and runway, DAU/MAU ratio, and churn rate. For pre-revenue startups: user growth, engagement, and activation rates. The specific metrics depend on your business model and stage.', sort_order: 247 },
  { id: 'dc-startup-0248', deck_id: 'deck-startup-fundamentals', front: 'What are the most common reasons startups fail?', back: 'Top reasons include: no market need (building something nobody wants), running out of cash, wrong team, getting outcompeted, pricing/cost issues, poor product, ignoring customers, mistiming the market, and losing focus. Most failures trace back to building something the market does not want.', sort_order: 248 },
  { id: 'dc-startup-0249', deck_id: 'deck-startup-fundamentals', front: 'What is an acquisition and how does the process work?', back: 'When a larger company buys a startup. The process includes initial interest, signing an LOI (Letter of Intent), due diligence, negotiation of purchase price and terms, definitive agreement, and closing. Payment can be cash, stock, or a combination. Typical process takes 2-6 months.', sort_order: 249 },
  { id: 'dc-startup-0250', deck_id: 'deck-startup-fundamentals', front: 'What is the Rule of 40 for SaaS companies?', back: 'A benchmark stating that a healthy SaaS company revenue growth rate plus profit margin should exceed 40%. For example, 30% growth + 15% profit margin = 45% (good). It balances growth and profitability — investors use it to evaluate whether a company is efficiently scaling.', sort_order: 250 },
];
